+/// Returns `true` if the golden directory exists and contains at least one `.db` file.
+fn golden_available() -> bool {
+    let dir = golden_dir();
+    dir.is_dir() && golden::discover_golden_files(&dir).is_ok_and(|v| !v.is_empty())
+}
